from flask import Flask, request, jsonify, make_response
from functools import wraps
import redis
import json
import uuid
import time
import hashlib

app = Flask(__name__)

redis_client = redis.Redis(host="localhost", port=6379, db=0, decode_responses=True)

SESSION_PREFIX = "session:"
CACHE_PREFIX = "cache:"
SESSION_TTL_SECONDS = 60 * 60 * 24
CACHE_TTL_SECONDS = 60


def get_cache_key(func_name, args, kwargs):
    raw = f"{func_name}:{args}:{sorted(kwargs.items())}"
    return CACHE_PREFIX + hashlib.sha256(raw.encode("utf-8")).hexdigest()


def cache(ttl=CACHE_TTL_SECONDS):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            cache_key = get_cache_key(func.__name__, args, kwargs)
            cached_value = redis_client.get(cache_key)
            if cached_value is not None:
                return json.loads(cached_value)

            result = func(*args, **kwargs)
            redis_client.set(cache_key, json.dumps(result), ex=ttl)
            return result
        return wrapper
    return decorator


def create_session(user_id, data=None):
    session_id = str(uuid.uuid4())
    payload = {
        "user_id": user_id,
        "created_at": int(time.time()),
        "data": data or {}
    }
    redis_client.set(f"{SESSION_PREFIX}{session_id}", json.dumps(payload), ex=SESSION_TTL_SECONDS)
    return session_id


def get_session(session_id):
    session_data = redis_client.get(f"{SESSION_PREFIX}{session_id}")
    if not session_data:
        return None
    return json.loads(session_data)


def update_session(session_id, data):
    key = f"{SESSION_PREFIX}{session_id}"
    session_data = redis_client.get(key)
    if not session_data:
        return False
    payload = json.loads(session_data)
    payload["data"] = data
    redis_client.set(key, json.dumps(payload), ex=SESSION_TTL_SECONDS)
    return True


def delete_session(session_id):
    return redis_client.delete(f"{SESSION_PREFIX}{session_id}") > 0


@cache(ttl=120)
def expensive_database_query(query_id):
    time.sleep(2)
    return {
        "query_id": query_id,
        "result": f"expensive result for {query_id}",
        "generated_at": int(time.time())
    }


@app.route("/login", methods=["POST"])
def login():
    body = request.get_json(force=True, silent=True) or {}
    user_id = body.get("user_id")
    if not user_id:
        return jsonify({"error": "user_id is required"}), 400

    session_id = create_session(user_id, data={"roles": ["user"]})
    response = make_response(jsonify({"message": "logged in", "session_id": session_id}))
    response.headers["X-Session-Id"] = session_id
    return response


@app.route("/session/<session_id>", methods=["GET"])
def session_lookup(session_id):
    session = get_session(session_id)
    if not session:
        return jsonify({"error": "session not found"}), 404
    return jsonify(session)


@app.route("/session/<session_id>", methods=["PUT"])
def session_update(session_id):
    body = request.get_json(force=True, silent=True) or {}
    data = body.get("data")
    if data is None:
        return jsonify({"error": "data is required"}), 400
    if not update_session(session_id, data):
        return jsonify({"error": "session not found"}), 404
    return jsonify({"message": "session updated"})


@app.route("/session/<session_id>", methods=["DELETE"])
def session_remove(session_id):
    if not delete_session(session_id):
        return jsonify({"error": "session not found"}), 404
    return jsonify({"message": "session deleted"})


@app.route("/query/<query_id>", methods=["GET"])
def query(query_id):
    result = expensive_database_query(query_id)
    return jsonify(result)


@app.route("/health", methods=["GET"])
def health():
    try:
        pong = redis_client.ping()
        return jsonify({"status": "ok", "redis": pong})
    except Exception as exc:
        return jsonify({"status": "error", "redis": False, "detail": str(exc)}), 500


